//! # IoT Residue Collector
//!
//! Ingests `rtl_433` JSON from stdin, parses it for key intelligence,
//! and forges a `PleromaticFrame` of type `Semantic`. This acts as a
//! "gateway" from the raw RF world to the Pleromatic mesh.

use distributed_inference::pleromatic_frame::{PleromaticFrame, PleromaticMediaType};
use serde_json::Value;
use std::io::{self, BufRead, Write};

fn main() {
    let stdin = io::stdin();
    for line in stdin.lock().lines() {
        let line = match line {
            Ok(l) => l,
            Err(_) => continue,
        };

        if let Ok(v) = serde_json::from_str::<Value>(&line) {
            if let Some(model) = v.get("model").and_then(|m| m.as_str()) {
                let temp = v.get("temperature_C").and_then(|t| t.as_f64());
                let humidity = v.get("humidity").and_then(|h| h.as_f64());
                let device_id = v.get("id").and_then(|i| i.as_i64());

                let mut fragments = vec![model.to_string()];
                if let Some(t) = temp {
                    fragments.push(format!("{:.1}C", t));
                }
                if let Some(h) = humidity {
                    fragments.push(format!("{}%", h as u8));
                }
                if let Some(id) = device_id {
                    fragments.push(format!("ID:{}", id));
                }

                let semantic_data = fragments.join(" ").as_bytes().to_vec();

                let frame = PleromaticFrame::grounding(
                    "rtl_433_gateway".to_string(),
                    PleromaticMediaType::Semantic,
                    semantic_data.clone(),
                );

                if let Ok(bytes) = bincode::serialize(&frame) {
                    if std::fs::write("iot_residue.frame", &bytes).is_ok() {
                        let log_msg = format!(
                            "[GATEWAY] RESOLVED: {}",
                            String::from_utf8_lossy(&semantic_data)
                        );
                        let _ = std::fs::OpenOptions::new()
                            .append(true)
                            .create(true)
                            .open("gateway.log")
                            .and_then(|mut f| writeln!(f, "{}", log_msg));
                        eprintln!("\x1b[38;5;51m{}\x1b[0m", log_msg);
                    }
                }
            }
        }
    }
}
